pages.css:
.page-01 {
  width: 1242px;
  height: 1660px;
  background-color: #F8F8F8;
  color: #111111;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  box-sizing: border-box;
  padding: 110px 100px;
  display: flex;
  flex-direction: column;
  position: relative;
}

.header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 200px;
}

.icon {
  font-size: 44px;
}

.label {
  font-size: 40px;
  font-weight: 600;
  color: #555555;
  letter-spacing: 0;
}

.title-section {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.title-line {
  font-size: 136px;
  font-weight: 900;
  line-height: 1.15;
  color: #111111;
  letter-spacing: 0;
}

.title-line.highlight {
  color: #E53935;
}

.content-section {
  margin-top: auto;
  display: flex;
  flex-direction: column;
  gap: 56px;
  background-color: #FFFFFF;
  padding: 64px 56px;
  border-radius: 16px;
  box-shadow: 0 20px 40px rgba(0,0,0,0.03);
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.sub-tag {
  font-size: 38px;
  font-weight: 800;
  color: #E53935;
  background-color: #FFEBEE;
  padding: 10px 24px;
  border-radius: 8px;
  width: fit-content;
  letter-spacing: 0;
}

.sub-text {
  font-size: 42px;
  line-height: 1.6;
  color: #333333;
  font-weight: 500;
  letter-spacing: 0;
}

.page-02 {
  width: 1242px;
  height: 1660px;
  background-color: #F2F4F7;
  box-sizing: border-box;
  padding: 100px 96px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  position: relative;
}

.page-header {
  display: flex;
  align-items: center;
  margin-bottom: 60px;
}

.header-icon {
  font-size: 44px;
  margin-right: 16px;
}

.header-label {
  font-size: 38px;
  color: #555555;
  font-weight: 600;
}

.title-section {
  margin-bottom: 72px;
}

.page-title {
  font-size: 108px;
  font-weight: 900;
  line-height: 1.25;
  color: #111111;
  letter-spacing: 0;
}

.content-section {
  flex: 1;
  display: flex;
  flex-direction: column;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.proof-item {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 40px 48px;
  display: flex;
  flex-direction: column;
  gap: 20px;
  box-shadow: 0 12px 32px rgba(0, 0, 0, 0.03);
}

.proof-tag {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  align-self: flex-start;
  background-color: #111111;
  color: #FFFFFF;
  font-size: 34px;
  font-weight: 700;
  padding: 10px 20px;
  border-radius: 8px;
}

.proof-text {
  font-size: 40px;
  line-height: 1.6;
  color: #222222;
  font-weight: 400;
}

.page-03 {
  width: 1242px;
  height: 1660px;
  background-color: #121212;
  color: #FFFFFF;
  box-sizing: border-box;
  padding: 96px 96px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
  position: relative;
}

.header {
  display: flex;
  align-items: center;
  gap: 16px;
  font-size: 38px;
  color: #888888;
  margin-bottom: 40px;
}

.title-section {
  margin-bottom: 56px;
}

.title-line {
  font-size: 96px;
  font-weight: 800;
  line-height: 1.25;
  color: #FFFFFF;
  margin: 0;
}

.metric-section {
  margin-bottom: 56px;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

.metric-highlight {
  font-size: 160px;
  font-weight: 900;
  color: #FFD700;
  line-height: 1.1;
}

.metric-sub {
  font-size: 38px;
  color: #A0A0A0;
  margin-top: 16px;
  padding-left: 16px;
  border-left: 6px solid #FFD700;
  line-height: 1.2;
}

.list-section {
  display: flex;
  flex-direction: column;
  gap: 36px;
  flex: 1;
}

.list-item {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-left: 24px;
  border-left: 4px solid #333333;
}

.item-tag {
  font-size: 36px;
  font-weight: 700;
  color: #FFD700;
}

.item-text {
  font-size: 38px;
  line-height: 1.5;
  color: #CCCCCC;
  margin: 0;
}

.footnote-section {
  font-size: 34px;
  color: #555555;
  text-align: left;
  margin-top: auto;
  line-height: 1.5;
}

.footnote-section p {
  margin: 0;
}

.page {
  width: 1242px;
  height: 1660px;
  background-color: #F4F4F2;
  padding: 112px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  position: relative;
}

.header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 80px;
}

.header-icon {
  font-size: 42px;
}

.header-label {
  font-size: 38px;
  font-weight: 600;
  color: #666;
  letter-spacing: 0;
}

.title-wrapper {
  margin-bottom: 120px;
}

.title-line {
  font-size: 120px;
  font-weight: 900;
  color: #1A1A1A;
  line-height: 1.25;
  letter-spacing: 0;
  margin: 0;
}

.list-wrapper {
  display: flex;
  flex-direction: column;
  flex: 1;
}

.list-item {
  display: flex;
  flex-direction: column;
  gap: 24px;
  padding-bottom: 56px;
  margin-bottom: 56px;
  border-bottom: 2px solid #E0E0DE;
}

.list-item:last-child {
  padding-bottom: 0;
  margin-bottom: 0;
  border-bottom: none;
}

.item-tag {
  display: inline-flex;
  align-items: center;
  gap: 16px;
  font-size: 38px;
  font-weight: 800;
  color: #D33F23;
  letter-spacing: 0;
  margin: 0;
}

.item-tag::before {
  content: "";
  display: block;
  width: 12px;
  height: 12px;
  background-color: #D33F23;
  border-radius: 2px;
}

.item-text {
  font-size: 42px;
  font-weight: 400;
  color: #333;
  line-height: 1.6;
  letter-spacing: 0;
  text-align: justify;
  margin: 0;
}

.page-06 {
  width: 1242px;
  height: 1660px;
  background-color: #F7F7F9;
  color: #1A1A1A;
  box-sizing: border-box;
  padding: 100px 100px;
  position: relative;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
}

.page-header {
  margin-bottom: 40px;
}

.label-group {
  display: flex;
  align-items: center;
  gap: 16px;
}

.icon {
  font-size: 40px;
}

.label {
  font-size: 38px;
  font-weight: 600;
  color: #666;
  letter-spacing: 0;
}

.title-section {
  margin-bottom: 60px;
}

.page-title {
  font-size: 110px;
  font-weight: 800;
  line-height: 1.2;
  letter-spacing: 0;
  color: #111;
}

.page-title p {
  margin: 0;
}

.content-section {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.sub-item {
  background-color: #FFFFFF;
  padding: 32px 40px;
  border-radius: 16px;
  border-left: 8px solid #E63946;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.03);
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.tag {
  display: inline-block;
  font-size: 36px;
  font-weight: 700;
  color: #E63946;
}

.text {
  font-size: 40px;
  line-height: 1.6;
  color: #333;
}

.steps-container {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.step-item {
  display: flex;
  gap: 24px;
  align-items: flex-start;
  background-color: #FFFFFF;
  padding: 32px 40px;
  border-radius: 16px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.03);
}

.step-num {
  font-size: 48px;
  font-weight: 900;
  color: #E63946;
  line-height: 1;
  padding-top: 6px;
  min-width: 60px;
}

.step-text {
  font-size: 40px;
  line-height: 1.5;
  color: #222;
  margin: 0;
}
